import React from "react";
import { BrowserRouter as Route, Switch } from "react-router-dom";
import { Landing } from "UserPages/Landing";
import { About } from "UserPages/About";
import { Contact } from "UserPages/Contact";
import { Solutions } from "UserPages/Solutions";

export const Pages = [
  { page: Landing, path: "HOME", component: Landing },
  { page: About, path: "/ABOUT", component: About },
  { page: Solutions, path: "/SOLUTIONS", component: Solutions },
  { page: Landing, path: "/", component: Landing },
  { page: Contact, path: "CONTACT", component: Contact },
];

export const ScreenLayoutInner = () => {
  return (
    <div>
      <Switch>
        {Pages.map((page, i) => (
          <Route path={page.path}>{page.component}</Route>
        ))}
      </Switch>
    </div>
  );
};
